sql:
SELECT AVG(pressure) AS average_pressure
FROM well_performance
WHERE well = '0';

SELECT well_name
FROM wells
ORDER BY well_id;

external_knowledge:
; Performance metrics include pressure, temperature, drawdown, back pressure, gas presence, water saturation, well model, and depth; 
; Maintenance and alert histories cover the activity, date, cost, and status of the latest maintenance, as well as the type, description, date, severity, status, and resolution date of the latest alert;
; The report provides a snapshot of each well's current status and recent activities.

sql:
SELECT MAX(pressure) AS highest_pressure
  FROM well_performance
  WHERE well = 'R_A2';

SELECT pressure
FROM well_performance
WHERE pressure > 300;

SELECT well_name 
FROM wells 
ORDER BY well_name;
